75	async function resolveNostrDirectAccess(params: {
76	  cfg: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["cfg"];
77	  accountId: string;
78	  dmPolicy: "pairing" | "allowlist" | "open" | "disabled";
79	  allowFrom: Array<string | number> | undefined;
80	  senderPubkey: string;
81	  rawBody: string;
82	  runtime: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["runtime"];
83	}) {
84	  return resolveInboundDirectDmAccessWithRuntime({
85	    cfg: params.cfg,
86	    channel: "nostr",
87	    accountId: params.accountId,
88	    dmPolicy: params.dmPolicy,
89	    allowFrom: params.allowFrom,
90	    senderId: params.senderPubkey,
91	    rawBody: params.rawBody,
92	    isSenderAllowed: isNostrSenderAllowed,
93	    runtime: params.runtime,
94	    modeWhenAccessGroupsOff: "configured",
95	  });
96	}
