export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      blurb: "Real-time bulletin board messaging via PulseBoard.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: {
      configPrefixes: ["channels.pulseboard"],
    },
    config: {
      listAccountIds: () => ["default"],
      defaultAccountId: () => "default",
      resolveAccount: () => ({
        accountId: "default",
        configured: false,
      }),
      isConfigured: (account: { configured?: boolean }) => account.configured === true,
      describeAccount: () => ({
        configured: false,
        extra: {},
      }),
    },
    setup: {
      applyAccountConfig: async () => {},
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(`[pulseboard] connecting to PulseBoard...`);
        return {
          stop: () => {
            ctx.log?.info(`[pulseboard] disconnected from PulseBoard`);
          },
        };
      },
    },
    messaging: {
      normalizeTarget: (target: string) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, text }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

